// Score lead from Apify data + Claude revenue estimate
// Scoring: employee count (0-5) + revenue (0-5) + title (0-3) = max 13 pts
const revenueResponse = $input.first().json;
const apify = $('Apify LinkedIn Scrape').first().json;
const lead = $('Loop Over Items').first().json;

// === PARSE CLAUDE REVENUE ESTIMATE ===
let revenue = 0;
let revenueConfidence = 'none';
let revenueReasoning = '';
try {
  const responseText = revenueResponse.content?.[0]?.text || revenueResponse.text || '';
  // Strip markdown code fences if present
  const cleaned = responseText.replace(/```json\n?|```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  revenue = Number(parsed.revenue_estimate) || 0;
  revenueConfidence = parsed.confidence || 'unknown';
  revenueReasoning = parsed.reasoning || '';
} catch(e) {
  revenueReasoning = 'Failed to parse revenue estimate';
}

// === EXTRACT DATA FROM APIFY SCRAPE ===
const personTitle = apify.experiences?.[0]?.title || apify.headline || '';
const companyName = apify.experiences?.[0]?.companyName || '';
const fullName = apify.fullName || lead.Name || '';

// Parse employee count from Apify
let employeeCount = 0;
const empSources = [
  apify.experiences?.[0]?.companyEmployees,
  apify.experiences?.[0]?.companySize,
  apify.experiences?.[0]?.companyStaffCountRange,
  apify.experiences?.[0]?.companyEmployeeCount,
  apify.companySize,
  apify.employeesCount
];
for (const empRaw of empSources) {
  if (empRaw == null) continue;
  if (typeof empRaw === 'number' && empRaw > 0) {
    employeeCount = empRaw;
    break;
  }
  if (typeof empRaw === 'string') {
    const rangeMatch = empRaw.match(/(\d[\d,]*)\s*[-–]\s*(\d[\d,]*)/);
    if (rangeMatch) {
      const low = parseInt(rangeMatch[1].replace(/,/g, ''));
      const high = parseInt(rangeMatch[2].replace(/,/g, ''));
      employeeCount = Math.round((low + high) / 2);
      break;
    }
    const numMatch = empRaw.match(/(\d[\d,]*)/);
    if (numMatch) {
      employeeCount = parseInt(numMatch[1].replace(/,/g, ''));
      break;
    }
  }
}

// ============ SCORING ALGORITHM (max 13 pts) ============
let score = 0;
let scoreBreakdown = [];

// 1. Employee Count (max 5 pts)
if (employeeCount >= 50 && employeeCount <= 200) {
  score += 5; scoreBreakdown.push('Employees 50-200: +5');
} else if (employeeCount >= 20 && employeeCount < 50) {
  score += 4; scoreBreakdown.push('Employees 20-49: +4');
} else if (employeeCount >= 10 && employeeCount < 20) {
  score += 3; scoreBreakdown.push('Employees 10-19: +3');
} else if (employeeCount > 200) {
  score += 3; scoreBreakdown.push('Employees 200+: +3');
} else if (employeeCount >= 5 && employeeCount < 10) {
  score += 2; scoreBreakdown.push('Employees 5-9 (below ICP): +2');
} else if (employeeCount > 0) {
  score += 1; scoreBreakdown.push('Employees <5: +1');
} else {
  scoreBreakdown.push('Employees unknown: +0');
}

// 2. Revenue (max 5 pts) — from Claude estimate
if (revenue >= 10000000) {
  score += 5; scoreBreakdown.push('Revenue $10M+ (est ' + revenueConfidence + '): +5');
} else if (revenue >= 5000000) {
  score += 4; scoreBreakdown.push('Revenue $5-10M (est ' + revenueConfidence + '): +4');
} else if (revenue >= 1000000) {
  score += 3; scoreBreakdown.push('Revenue $1-5M (est ' + revenueConfidence + '): +3');
} else if (revenue > 0) {
  score += 1; scoreBreakdown.push('Revenue <$1M (est ' + revenueConfidence + '): +1');
} else {
  scoreBreakdown.push('Revenue unknown: +0');
}

// 3. Title (max 3 pts)
const titleLower = personTitle.toLowerCase();
if (/\b(ceo|founder|co-founder|owner)\b/.test(titleLower)) {
  score += 3; scoreBreakdown.push('CEO/Founder/Owner: +3');
} else if (/\b(coo|president|vp|vice president|chief)\b/.test(titleLower)) {
  score += 2; scoreBreakdown.push('COO/President/VP/Chief: +2');
} else if (/\b(director|head of)\b/.test(titleLower)) {
  score += 1; scoreBreakdown.push('Director/Head: +1');
} else if (personTitle) {
  scoreBreakdown.push('Other title: +0');
} else {
  scoreBreakdown.push('Title unknown: +0');
}

// ============ FLAGS ============
const flags = [];
if (employeeCount > 0 && employeeCount < 10) {
  flags.push('BELOW ICP: ' + employeeCount + ' employees');
}

// ============ TIER ASSIGNMENT ============
let tier, outreachType;
if (score >= 10) {
  tier = 'Tier 1'; outreachType = 'Loom Video (Priority)';
} else if (score >= 7) {
  tier = 'Tier 2'; outreachType = 'Loom Video';
} else if (score >= 4) {
  tier = 'Tier 3'; outreachType = 'Personalized Text';
} else {
  tier = 'Tier 4'; outreachType = 'Template Outreach';
}

const revenueDisplay = revenue > 0
  ? '$' + (revenue / 1000000).toFixed(1) + 'M (' + revenueConfidence + ')'
  : 'Unknown';

// Pass through ALL Apify data (so Claude Research Script prompt still works)
return [{
  json: {
    ...apify,
    _score: score,
    _tier: tier,
    _outreach_type: outreachType,
    _employee_count: employeeCount,
    _revenue: revenue,
    _revenue_display: revenueDisplay,
    _revenue_reasoning: revenueReasoning,
    _company_name: companyName,
    _person_title: personTitle,
    _score_breakdown: scoreBreakdown.join(' | '),
    _flags: flags.join(' | '),
    _full_name: fullName
  }
}];

